                WriteLiteral(@"    <script>
        $('#aquarioId').change(function () {
            var id = $(this).val();
            if (!id) {
                $('#infoAquario').hide();
                return;
            }
            $.get('/Peixe/InfoAquario', { id: id }, function (data) {
                if (data.sucesso) {
                    $('#infoAquario').html(
                        '<strong>' + data.nome + '</strong> — ' +
                        data.capacidade + ' L, água ' + data.tipoAgua +
                        ' (Responsável: ' + data.responsavel + ')'
                    ).show();
                } else {
                    $('#infoAquario').text(data.mensagem).show();
                }
            });
        });

        $('#btnDetectarIA').click(function () {
            var fileInput = $('#arquivoFoto')[0];
            if (!fileInput || !fileInput.files || fileInput.files.length === 0) {
                $('#iaStatus').text('Selecione uma imagem primeiro.');
                return;
    ");
                WriteLiteral(@"        }

            var fd = new FormData();
            fd.append('arquivoFoto', fileInput.files[0]);

            $('#iaStatus').text('Analisando imagem...');
            $.ajax({
                url: '/Peixe/DetectarParametros',
                method: 'POST',
                data: fd,
                processData: false,
                contentType: false
            }).done(function (data) {
                if (data && data.sucesso) {
                    if (data.especie) $('#Especie').val(data.especie);
                    if (data.nomeCientifico) $('#NomeCientifico').val(data.nomeCientifico);
                    if (data.temperaturaIdeal !== null && data.temperaturaIdeal !== undefined)
                        $('#TemperaturaIdeal').val(data.temperaturaIdeal);
                    if (data.luminosidadeIdeal !== null && data.luminosidadeIdeal !== undefined)
                        $('#LuminosidadeIdeal').val(data.luminosidadeIdeal);
                    $('#iaStatus').text('Parâmetros");
                WriteLiteral(@" preenchidos.');
                } else {
                    $('#iaStatus').text(data && data.mensagem ? data.mensagem : 'Falha ao analisar.');
                }
            }).fail(function () {
                $('#iaStatus').text('Erro ao chamar a IA.');
            });
        });

        $('#btnDetectarEspecieIA').click(function () {
            var especie = $('#Especie').val();
            if (!especie) {
                $('#iaStatus').text('Informe a espécie primeiro.');
                return;
            }

            $('#iaStatus').text('Consultando IA pela espécie...');
            $.post('/Peixe/DetectarParametrosPorEspecie', { especie: especie })
                .done(function (data) {
                    if (data && data.sucesso) {
                        if (data.especie) $('#Especie').val(data.especie);
                        if (data.nomeCientifico) $('#NomeCientifico').val(data.nomeCientifico);
                        if (data.temperaturaIdeal !== null && data.tempe");
