                        $('#iaStatus').text('Parâmetros preenchidos.');
                    } else {
                        $('#iaStatus').text(data && data.mensagem ? data.mensagem : 'Falha ao analisar.');
                    }
                })
                .fail(function () {
                    $('#iaStatus').text('Erro ao chamar a IA.');
                });
        });
    </script>
